+// =========================================================================
+// SemanticSearchHit — serde roundtrip
+// =========================================================================
+
+proptest! {
+    #![proptest_config(ProptestConfig::with_cases(50))]
+
+    #[test]
+    fn prop_semantic_search_hit_serde(
+        segment_id in 0_i64..100_000,
